// ===================================================================
// 제4장 보강: 데이터 구조화 (v5.8.1) - 제네릭 설계
// ===================================================================
//
// 철학: "타입으로부터의 자유"
//
// v5.8: 구체적인 타입들의 통합
// v5.8.1: 모든 타입에 대응하는 추상 설계 ← 여기!
//
// 제네릭은:
// - 구체적 타입 대신 임시 문자 T를 사용
// - 컴파일 타임에 각 타입별로 코드 생성
// - 런타임 성능 저하 없음 (Zero-Cost Abstraction)
// - 코드 재사용성의 극대화
//
// 핵심: "범용성과 성능의 완벽한 조화"
//
// ===================================================================

fn main() {
    println!("╔═══════════════════════════════════════════════════════════╗");
    println!("║v5.8.1: 제네릭 설계의 유연성 (Generic Data Structures)   ║");
    println!("║       \"어떤 타입이든 담을 수 있는 만능 설계도\"         ║");
    println!("╚═══════════════════════════════════════════════════════════╝\n");

    section_1_generic_basics();
    println!();
    section_2_generic_structs();
    println!();
    section_3_generic_methods();
    println!();
    section_4_generic_enums();
    println!();
    section_5_multiple_type_params();
    println!();
    section_6_generic_functions();
    println!();
    section_7_practical_examples();
}

// ===================================================================
// Section 1: 제네릭의 기본 개념
// ===================================================================
//
// 제네릭이란 무엇인가, 왜 필요한가를 배웁니다.
//
fn section_1_generic_basics() {
    println!("▶ Section 1: 제네릭의 기본 개념");
    println!("─────────────────────────────────────────\n");

    // ─────────────────────────────────────────
    // 1-1. 제네릭이 없는 설계
    // ─────────────────────────────────────────
    println!("  [1-1] 제네릭 없이는?");

    struct IntContainer {
        data: i32,
    }

    struct StringContainer {
        data: String,
    }

    struct FloatContainer {
        data: f64,
    }

    println!("    ❌ 각 타입마다 별도 구조체 정의 필요:");
    println!("       IntContainer, StringContainer, FloatContainer, ...");
    println!("    → 코드 중복, 유지보수 어려움\n");

    // ─────────────────────────────────────────
    // 1-2. 제네릭의 해결책
    // ─────────────────────────────────────────
    println!("  [1-2] 제네릭 도입");

    struct Container<T> {
        data: T,
    }

    println!("    ✅ 하나의 구조체로 모든 타입 대응:");
    println!("       Container<i32>, Container<String>, Container<f64>, ...");
    println!("    → 코드 재사용, 유지보수 용이\n");

    // ─────────────────────────────────────────
    // 1-3. 컴파일 타임 구체화 (Monomorphization)
    // ─────────────────────────────────────────
    println!("  [1-3] 컴파일 타임 구체화");

    println!("    런타임에 인식하는 것이 아니라,");
    println!("    컴파일러가 각 타입에 맞는 코드를 생성합니다:");
    println!();
    println!("    제네릭 코드:");
    println!("      struct Container<T> {{ data: T }}");
    println!();
    println!("    ↓ 컴파일러가 생성 ↓");
    println!();
    println!("    구체적 코드:");
    println!("      struct Container<i32> {{ data: i32 }}");
    println!("      struct Container<String> {{ data: String }}");
    println!("      struct Container<f64> {{ data: f64 }}");
    println!("      ...");
    println!();
    println!("    성능: 런타임 오버헤드 없음 (Zero-Cost Abstraction)\n");

    println!("  💡 핵심: T는 일반화된 타입 매개변수, 컴파일 타임에 구체화됩니다.\n");
}

// ===================================================================
// Section 2: 제네릭 구조체
// ===================================================================
//
// 제네릭을 사용한 구조체 설계를 배웁니다.
//
fn section_2_generic_structs() {
    println!("▶ Section 2: 제네릭 구조체");
    println!("─────────────────────────────────────────\n");

    // ─────────────────────────────────────────
    // 2-1. 기본 제네릭 구조체
    // ─────────────────────────────────────────
    println!("  [2-1] 기본 제네릭 구조체");

    struct GogsEnvelope<T> {
        id: u32,
        data: T,
    }

    impl<T> GogsEnvelope<T> {
        fn new(id: u32, data: T) -> Self {
            GogsEnvelope { id, data }
        }

        fn get_id(&self) -> u32 {
            self.id
        }

        fn peek(&self) -> &T {
            &self.data
        }
    }

    // 다양한 타입으로 사용
    let int_env = GogsEnvelope::new(1, 42);
    let str_env = GogsEnvelope::new(2, String::from("Hello"));
    let float_env = GogsEnvelope::new(3, 3.14);

    println!("    정수 봉투 #{}: {:?}", int_env.get_id(), int_env.peek());
    println!("    문자열 봉투 #{}: {:?}", str_env.get_id(), str_env.peek());
    println!("    실수 봉투 #{}: {:?}\n", float_env.get_id(), float_env.peek());

    // ─────────────────────────────────────────
    // 2-2. 여러 필드가 제네릭
    // ─────────────────────────────────────────
    println!("  [2-2] 여러 필드가 제네릭");

    struct Pair<T> {
        first: T,
        second: T,
    }

    let pair1 = Pair {
        first: 1,
        second: 2,
    };

    let pair2 = Pair {
        first: "a",
        second: "b",
    };

    println!("    정수 쌍: ({}, {})", pair1.first, pair1.second);
    println!("    문자 쌍: ({}, {})\n", pair2.first, pair2.second);

    println!("  💡 핵심: 구조체에서 T는 인스턴스마다 구체적인 타입으로 결정됩니다.\n");
}

// ===================================================================
// Section 3: 제네릭 메서드
// ===================================================================
//
// 제네릭 구조체의 메서드 구현을 배웁니다.
//
fn section_3_generic_methods() {
    println!("▶ Section 3: 제네릭 메서드");
    println!("─────────────────────────────────────────\n");

    // ─────────────────────────────────────────
    // 3-1. 제네릭 메서드 구현
    // ─────────────────────────────────────────
    println!("  [3-1] 제네릭 메서드");

    struct Container<T> {
        data: T,
    }

    impl<T> Container<T> {
        // 일반 메서드
        fn get(&self) -> &T {
            &self.data
        }

        // 가변 참조 메서드
        fn get_mut(&mut self) -> &mut T {
            &mut self.data
        }

        // 소유권 이동 메서드
        fn into_data(self) -> T {
            self.data
        }

        // 변환 메서드
        fn map<U, F>(self, f: F) -> Container<U>
        where
            F: Fn(T) -> U,
        {
            Container { data: f(self.data) }
        }
    }

    // 사용 예
    let mut container = Container { data: 5 };

    println!("    데이터: {}", container.get());

    *container.get_mut() *= 2;
    println!("    수정 후: {}", container.get());

    let doubled = container.map(|x| x * 2);
    println!("    변환 후: {}\n", doubled.get());

    // ─────────────────────────────────────────
    // 3-2. 타입 바운드가 있는 메서드
    // ─────────────────────────────────────────
    println!("  [3-2] 타입 바운드 (미리보기)");

    struct Displayable<T: std::fmt::Display> {
        data: T,
    }

    impl<T: std::fmt::Display> Displayable<T> {
        fn display(&self) {
            println!("    데이터: {}", self.data);
        }
    }

    let num = Displayable { data: 42 };
    num.display();

    let text = Displayable {
        data: "hello",
    };
    text.display();
    println!();

    println!("  💡 핵심: impl<T>와 fn() 모두에서 제네릭을 사용할 수 있습니다.\n");
}

// ===================================================================
// Section 4: 제네릭 열거형
// ===================================================================
//
// 표준 라이브러리의 Option<T>, Result<T, E>처럼 제네릭 열거형을 배웁니다.
//
fn section_4_generic_enums() {
    println!("▶ Section 4: 제네릭 열거형");
    println!("─────────────────────────────────────────\n");

    // ─────────────────────────────────────────
    // 4-1. 기본 제네릭 열거형
    // ─────────────────────────────────────────
    println!("  [4-1] 기본 제네릭 열거형");

    enum Status<T> {
        Success(T),
        Error(String),
        Pending,
    }

    let success_status: Status<i32> = Status::Success(42);
    let error_status: Status<String> = Status::Error("Failed".to_string());

    println!("    성공 상태: {:?}", matches!(success_status, Status::Success(_)));
    println!("    실패 상태: {:?}", matches!(error_status, Status::Error(_)));
    println!();

    // ─────────────────────────────────────────
    // 4-2. 표준 라이브러리의 제네릭 열거형
    // ─────────────────────────────────────────
    println!("  [4-2] Option<T>와 Result<T, E>");

    println!("    Option<T>:");
    println!("      enum Option<T> {{");
    println!("          Some(T),");
    println!("          None,");
    println!("      }}");
    println!();

    println!("    Result<T, E>:");
    println!("      enum Result<T, E> {{");
    println!("          Ok(T),");
    println!("          Err(E),");
    println!("      }}");
    println!();

    let value: Option<i32> = Some(42);
    match value {
        Some(n) => println!("    Some: {}", n),
        None => println!("    None"),
    }

    let result: Result<i32, String> = Ok(100);
    match result {
        Ok(n) => println!("    Ok: {}", n),
        Err(e) => println!("    Err: {}", e),
    }
    println!();

    println!("  💡 핵심: 열거형도 제네릭으로 유연하게 표현할 수 있습니다.\n");
}

// ===================================================================
// Section 5: 여러 타입 파라미터
// ===================================================================
//
// K, V, T 등 여러 타입 파라미터를 사용합니다.
//
fn section_5_multiple_type_params() {
    println!("▶ Section 5: 여러 타입 파라미터");
    println!("─────────────────────────────────────────\n");

    // ─────────────────────────────────────────
    // 5-1. 두 개의 타입 파라미터
    // ─────────────────────────────────────────
    println!("  [5-1] 두 개의 타입 파라미터");

    struct Pair<T, U> {
        first: T,
        second: U,
    }

    let pair1 = Pair {
        first: 5,
        second: "hello",
    };

    let pair2 = Pair {
        first: "key",
        second: 42,
    };

    println!("    정수-문자 쌍: ({}, {})", pair1.first, pair1.second);
    println!("    문자-정수 쌍: ({}, {})", pair2.first, pair2.second);
    println!();

    // ─────────────────────────────────────────
    // 5-2. 명확한 이름의 타입 파라미터
    // ─────────────────────────────────────────
    println!("  [5-2] 의미있는 타입 파라미터 이름");

    struct HashMap<K, V> {
        // K: Key, V: Value
        _key: K,
        _value: V,
    }

    println!("    HashMap<K, V>:");
    println!("      K: Key 타입");
    println!("      V: Value 타입");
    println!();

    enum Result<T, E> {
        // T: Type (성공 값), E: Error
        Ok(T),
        Err(E),
    }

    println!("    Result<T, E>:");
    println!("      T: Type (성공 값)");
    println!("      E: Error (실패 값)");
    println!();

    println!("  💡 핵심: T, K, V, E 등 의미있는 이름으로 의도를 명확히 합니다.\n");
}

// ===================================================================
// Section 6: 제네릭 함수
// ===================================================================
//
// 제네릭 함수와 메서드의 고급 사용을 배웁니다.
//
fn section_6_generic_functions() {
    println!("▶ Section 6: 제네릭 함수");
    println!("─────────────────────────────────────────\n");

    // ─────────────────────────────────────────
    // 6-1. 기본 제네릭 함수
    // ─────────────────────────────────────────
    println!("  [6-1] 제네릭 함수");

    fn print_value<T: std::fmt::Display>(value: T) {
        println!("    값: {}", value);
    }

    print_value(42);
    print_value("hello");
    print_value(3.14);
    println!();

    // ─────────────────────────────────────────
    // 6-2. 제네릭 반환 타입
    // ─────────────────────────────────────────
    println!("  [6-2] 제네릭 반환 타입");

    fn create_pair<T>(value: T) -> (T, T)
    where
        T: Clone,
    {
        (value.clone(), value)
    }

    let pair = create_pair(5);
    println!("    쌍: ({}, {})", pair.0, pair.1);
    println!();

    // ─────────────────────────────────────────
    // 6-3. 제네릭 함수 활용
    // ─────────────────────────────────────────
    println!("  [6-3] 배열 검색 함수");

    fn find_max<T: PartialOrd>(arr: &[T]) -> Option<&T> {
        arr.iter().max_by(|a, b| a.partial_cmp(b).unwrap())
    }

    let numbers = vec![3, 1, 4, 1, 5, 9];
    if let Some(max) = find_max(&numbers) {
        println!("    최대값: {}", max);
    }
    println!();

    println!("  💡 핵심: 함수도 제네릭으로 유연하게 설계할 수 있습니다.\n");
}

// ===================================================================
// Section 7: 실전 예제 - 범용 컨테이너
// ===================================================================
//
// 제네릭을 활용한 실무 수준의 구조체를 구현합니다.
//
fn section_7_practical_examples() {
    println!("▶ Section 7: 실전 예제");
    println!("─────────────────────────────────────────\n");

    // ─────────────────────────────────────────
    // 예제 1: 범용 스택
    // ─────────────────────────────────────────
    println!("  [예제 1] 범용 스택");

    struct Stack<T> {
        items: Vec<T>,
    }

    impl<T> Stack<T> {
        fn new() -> Self {
            Stack {
                items: Vec::new(),
            }
        }

        fn push(&mut self, item: T) {
            self.items.push(item);
        }

        fn pop(&mut self) -> Option<T> {
            self.items.pop()
        }

        fn is_empty(&self) -> bool {
            self.items.is_empty()
        }
    }

    let mut stack: Stack<i32> = Stack::new();
    stack.push(1);
    stack.push(2);
    stack.push(3);

    while let Some(item) = stack.pop() {
        println!("    꺼낸 항목: {}", item);
    }
    println!();

    // ─────────────────────────────────────────
    // 예제 2: 범용 키-값 저장소
    // ─────────────────────────────────────────
    println!("  [예제 2] 범용 저장소");

    struct Vault<K, V> {
        data: Vec<(K, V)>,
    }

    impl<K: PartialEq, V> Vault<K, V> {
        fn new() -> Self {
            Vault { data: Vec::new() }
        }

        fn insert(&mut self, key: K, value: V) {
            self.data.push((key, value));
        }

        fn get(&self, key: &K) -> Option<&V> {
            self.data
                .iter()
                .find(|(k, _)| k == key)
                .map(|(_, v)| v)
        }
    }

    let mut vault: Vault<String, i32> = Vault::new();
    vault.insert(String::from("alice"), 30);
    vault.insert(String::from("bob"), 25);

    if let Some(age) = vault.get(&String::from("alice")) {
        println!("    alice의 나이: {}", age);
    }
    println!();

    // ─────────────────────────────────────────
    // 예제 3: 범용 옵션 래퍼
    // ─────────────────────────────────────────
    println!("  [예제 3] 범용 래퍼");

    struct Wrapper<T> {
        value: Option<T>,
    }

    impl<T> Wrapper<T> {
        fn new(value: T) -> Self {
            Wrapper {
                value: Some(value),
            }
        }

        fn map<U, F>(self, f: F) -> Wrapper<U>
        where
            F: Fn(T) -> U,
        {
            Wrapper {
                value: self.value.map(f),
            }
        }

        fn unwrap_or(self, default: T) -> T {
            self.value.unwrap_or(default)
        }
    }

    let wrapper = Wrapper::new(5);
    let result = wrapper
        .map(|x| x * 2)
        .map(|x| x + 1)
        .unwrap_or(0);

    println!("    변환 결과: {}", result);
    println!();

    println!("  💡 핵심: 제네릭으로 실무 수준의 범용 도구를 설계할 수 있습니다.\n");
}

// ===================================================================
// 마무리: v5.8.1의 의미
// ===================================================================
//
// 요약:
// 1. 제네릭은 구체적 타입 대신 T를 사용
// 2. 컴파일 타임에 각 타입별 코드 생성
// 3. 런타임 성능 저하 없음 (Zero-Cost Abstraction)
// 4. 코드 재사용성 극대화
// 5. 추상화 수준의 획기적 향상
// 6. 어떤 타입이든 대응 가능한 설계
//
// ═══════════════════════════════════════════════════════════════
